+    // =========================================================================
+    // Q-Healing: Quantization Healing via Deep Sleep
+    // =========================================================================
+
+    /// Initialize Q-Healing controller
+    /// Call this after model is loaded with the model's layer count
+    pub fn initQHealing(
+        self: *Hippocampus,
+        n_layers: u32,
+        config: QHealingConfig,
+        model_hash: u64,
+    ) !void {
+        if (self.q_healer != null) {
+            logger.debug("Q-Healer already initialized", .{});
+            return;
+        }
+
+        self.n_model_layers = n_layers;
+
+        // Create Q-Healing controller
+        self.q_healer = try self.allocator.create(QHealingController);
+        errdefer {
+            self.allocator.destroy(self.q_healer.?);
+            self.q_healer = null;
+        }
+
+        self.q_healer.?.* = try QHealingController.init(
+            self.allocator,
+            config,
+            model_hash,
+        );
+
+        logger.info("Q-Healing controller initialized ({d} layers, budget: {d:.1}GB)", .{
+            n_layers,
+            config.repair_memory_budget_gb,
+        });
+    }
+
+    /// Try to enter deep sleep for Q-Healing
+    /// Transitions: DREAMING → DEEP_SLEEP after training AND idle >= min_idle_ms
+    pub fn tryDeepSleep(self: *Hippocampus) !void {
+        // Only transition from dreaming to deep_sleep (after consolidation training)
+        const current = self.state.load(.monotonic);
+        if (current != .dreaming) return;
+
+        // Check if deep sleep is enabled
+        if (!self.deep_sleep_config.enabled) return;
+
+        // Check if Q-Healer is initialized
+        if (self.q_healer == null) {
+            logger.debug("Q-Healer not initialized, skipping deep sleep", .{});
+            return;
+        }
+
+        // Check if we have a reference model for healing
+        const healer = self.q_healer.?;
+        if (healer.config.reference_model_path == null) {
+            logger.debug("No reference model configured, skipping deep sleep", .{});
+            return;
+        }
+
+        // Check idle time (need extended idle for deep sleep)
+        const now = std.time.milliTimestamp();
+        const idle_time = now - self.last_activity_time;
+        if (idle_time < self.deep_sleep_config.min_idle_ms) {
+            logger.debug("Not enough idle time for deep sleep ({d}ms < {d}ms)", .{
+                idle_time,
+                self.deep_sleep_config.min_idle_ms,
+            });
+            return;
+        }
+
+        // All conditions met - enter deep sleep
+        logger.info("Hippocampus: Entering deep sleep for Q-Healing (idle: {d}ms)", .{idle_time});
+        self.state.store(.deep_sleep, .monotonic);
+
+        // Spawn deep sleep thread
+        self.deep_sleep_thread = try std.Thread.spawn(.{}, deepSleepEntryPoint, .{self});
+    }
+
+    /// Deep sleep thread entry point for Q-Healing
+    fn deepSleepEntryPoint(self: *Hippocampus) void {
+        defer {
+            self.deep_sleep_thread = null;
+            // Return to awake state when done
+            self.state.store(.awake, .monotonic);
+            logger.info("Hippocampus: Waking from deep sleep", .{});
+        }
+
+        // Verify we're still in deep_sleep state
+        if (self.state.load(.monotonic) != .deep_sleep) {
+            logger.debug("Deep sleep cancelled before start", .{});
+            return;
+        }
+
+        const healer = self.q_healer orelse {
+            logger.warn("Q-Healer not available for deep sleep", .{});
+            return;
+        };
+
+        // Enter deep sleep mode in the healer
+        const entered = healer.enterDeepSleep(self.n_model_layers) catch |err| {
+            logger.err("Failed to enter deep sleep: {}", .{err});
+            return;
+        };
+
+        if (!entered) {
+            logger.debug("Deep sleep skipped (healer declined)", .{});
+            return;
+        }
+
+        // Run layer-by-layer repair
+        const start_time = std.time.milliTimestamp();
+        const max_duration = self.deep_sleep_config.max_duration_ms;
+
+        healer.repairLayers() catch |err| {
+            logger.err("Layer repair failed: {}", .{err});
+            healer.exitDeepSleep();
+            return;
+        };
+
+        const elapsed = std.time.milliTimestamp() - start_time;
+
+        // Check if we were interrupted
+        if (self.state.load(.monotonic) != .deep_sleep) {
+            logger.info("Deep sleep interrupted after {d}ms", .{elapsed});
+            healer.exitDeepSleep();
+            return;
+        }
+
+        // Check timeout
+        if (elapsed >= max_duration) {
+            logger.info("Deep sleep reached max duration ({d}ms)", .{max_duration});
+        }
+
+        // Exit deep sleep and apply healing adapter
+        healer.exitDeepSleep();
+
+        // Validate the healing adapter using dream validation
+        if (self.validation_config.enabled and self.dream_validator_instance != null) {
+            const healing_path = healer.getHealingAdapterPath();
+            if (healing_path) |path| {
+                logger.info("Validating healing adapter...", .{});
+                const result = self.dream_validator_instance.?.validateAdapter(path) catch |err| {
+                    logger.warn("Healing adapter validation error: {}", .{err});
+                    return;
+                };
+
+                if (!result.passed) {
+                    logger.warn("Healing adapter failed validation, not activating", .{});
+                    return;
+                }
+
+                logger.info("Healing adapter validated (score: {d:.1}%)", .{
+                    result.aggregate_score * 100,
+                });
+            }
+        }
+
+        logger.info("Q-Healing cycle complete (elapsed: {d}ms)", .{elapsed});
+    }
+
+    /// Check if deep sleep (Q-Healing) is currently active
+    pub fn isDeepSleeping(self: *const Hippocampus) bool {
+        return self.state.load(.monotonic) == .deep_sleep;
+    }
+
+    /// Configure deep sleep parameters
+    pub fn setDeepSleepConfig(self: *Hippocampus, config: DeepSleepConfig) void {
+        self.deep_sleep_config = config;
+        logger.debug("Deep sleep config updated (enabled: {}, min_idle: {d}ms)", .{
+            config.enabled,
+            config.min_idle_ms,
+        });
+    }
+
+    /// Get Q-Healing statistics
+    pub fn getQHealingStats(self: *const Hippocampus) struct {
+        enabled: bool,
+        healer_initialized: bool,
+        n_model_layers: u32,
+        is_deep_sleeping: bool,
+    } {
+        return .{
+            .enabled = self.deep_sleep_config.enabled,
+            .healer_initialized = self.q_healer != null,
+            .n_model_layers = self.n_model_layers,
+            .is_deep_sleeping = self.isDeepSleeping(),
+        };
+    }
 };

