+const std = @import("std");
+const logger = @import("logger.zig");
+const mixed_precision = @import("mixed_precision.zig");
+const QuantType = mixed_precision.QuantType;
+
+// =============================================================================
+// Layer Repair: Per-Layer Disk Paging and Precision Repair
+// =============================================================================
+//
+// During deep sleep, this module loads individual layers from a high-precision
+// reference model (FP16 or Q8), compares them against the Q2_K runtime model,
+// and computes LoRA correction gradients to bridge the precision gap.
+//
+// Memory Management Strategy:
+// - Only ONE layer is loaded at a time (~400-500MB for 30B model)
+// - Layer is freed immediately after gradient computation
+// - Strict memory budget enforcement to prevent OOM
+// =============================================================================
+
+/// Result of repairing a single layer
+pub const LayerRepairResult = struct {
+    /// Layer index that was repaired
+    layer_idx: u32,
+    /// Mean squared error before repair
+    error_before: f32,
+    /// Estimated error after repair (from gradient magnitude)
+    error_after: f32,
+    /// L2 norm of computed gradients
+    gradient_norm: f32,
+    /// Time taken for this layer repair (ms)
+    time_ms: u64,
+    /// Whether repair was successful
+    success: bool,
+    /// Error message if failed
+    error_message: ?[]const u8,
+};
+
+/// Metrics for the entire repair session
+pub const RepairMetrics = struct {
+    /// Number of layers processed
+    layers_processed: u32,
+    /// Total error reduction achieved
+    total_error_reduced: f32,
+    /// Total time elapsed (ms)
+    time_elapsed_ms: i64,
+    /// Peak memory usage during session (bytes)
+    memory_peak_bytes: usize,
+    /// Number of layers skipped (below threshold)
+    layers_skipped: u32,
+    /// Number of layers failed
+    layers_failed: u32,
+
+    pub fn init() RepairMetrics {
+        return .{
+            .layers_processed = 0,
+            .total_error_reduced = 0.0,
+            .time_elapsed_ms = 0,
+            .memory_peak_bytes = 0,
+            .layers_skipped = 0,
+            .layers_failed = 0,
+        };
+    }
+};
+
+/// High-precision layer loaded from disk
+pub const HighPrecLayer = struct {
+    /// Layer index
+    layer_idx: u32,
+    /// Layer weights (aligned for SIMD)
+    weights: []align(64) f16,
+    /// Size in bytes
+    size_bytes: usize,
+    /// Source file path
+    source_path: []const u8,
+    /// Quantization type of source
+    source_quant: QuantType,
+
+    pub fn deinit(self: *HighPrecLayer, allocator: std.mem.Allocator) void {
+        allocator.free(self.weights);
+        allocator.free(self.source_path);
+    }
+};
+
+/// Accumulated gradients for LoRA correction
+pub const GradientAccumulator = struct {
+    allocator: std.mem.Allocator,
+    /// Per-layer gradient buffers (layer_idx -> gradients)
+    layer_gradients: std.AutoHashMap(u32, []f32),
+    /// Total gradient norm for convergence check
+    total_norm: f32,
+    /// Number of accumulated batches
+    batch_count: u32,
+    /// Maximum gradient norm (for clipping)
+    max_grad_norm: f32,
+
+    const Self = @This();
+
+    pub fn init(allocator: std.mem.Allocator) Self {
+        return .{
+            .allocator = allocator,
+            .layer_gradients = std.AutoHashMap(u32, []f32).init(allocator),
+            .total_norm = 0.0,
+            .batch_count = 0,
+            .max_grad_norm = 1.0, // Default gradient clipping
+        };
+    }
+
+    pub fn deinit(self: *Self) void {
+        var it = self.layer_gradients.iterator();
+        while (it.next()) |entry| {
+            self.allocator.free(entry.value_ptr.*);
+        }
+        self.layer_gradients.deinit();
+    }
+
+    /// Add gradients for a layer
+    pub fn addGradients(self: *Self, layer_idx: u32, gradients: []const f32) !void {
+        // Compute gradient norm
+        var norm: f32 = 0.0;
+        for (gradients) |g| {
+            norm += g * g;
+        }
+        norm = @sqrt(norm);
+
+        // Apply gradient clipping if needed
+        var scale: f32 = 1.0;
+        if (norm > self.max_grad_norm) {
+            scale = self.max_grad_norm / norm;
+            logger.debug("Clipping gradients for layer {d}: norm {d:.4} -> {d:.4}", .{
+                layer_idx,
+                norm,
+                self.max_grad_norm,
+            });
+        }
+
+        if (self.layer_gradients.get(layer_idx)) |existing| {
+            // Accumulate to existing
+            for (existing, 0..) |*e, i| {
+                if (i < gradients.len) {
+                    e.* += gradients[i] * scale;
+                }
+            }
+        } else {
+            // Create new entry
+            const new_grads = try self.allocator.alloc(f32, gradients.len);
+            for (new_grads, 0..) |*g, i| {
+                g.* = gradients[i] * scale;
+            }
+            try self.layer_gradients.put(layer_idx, new_grads);
+        }
+
+        self.total_norm += norm * scale;
+        self.batch_count += 1;
+    }
+
+    /// Clear all accumulated gradients
+    pub fn clear(self: *Self) void {
+        var it = self.layer_gradients.iterator();
+        while (it.next()) |entry| {
+            self.allocator.free(entry.value_ptr.*);
+        }
+        self.layer_gradients.clearRetainingCapacity();
+        self.total_norm = 0.0;
+        self.batch_count = 0;
+    }
+
+    /// Get average gradient norm
+    pub fn getAverageNorm(self: *const Self) f32 {
+        if (self.batch_count == 0) return 0.0;
+        return self.total_norm / @as(f32, @floatFromInt(self.batch_count));
+    }
+};
+
+/// State for layer-by-layer precision repair
+pub const LayerRepairState = struct {
+    allocator: std.mem.Allocator,
+
+    /// Current layer being processed
+    current_layer: u32,
+    /// Total number of layers in model
+    total_layers: u32,
+
+    /// Memory budget for repair operations (bytes)
+    memory_budget_bytes: usize,
+    /// Current memory usage (bytes)
+    current_memory_bytes: usize,
+
+    /// Currently loaded high-precision layer (if any)
+    high_prec_layer: ?*HighPrecLayer,
+
+    /// Accumulated gradients for LoRA
+    accumulated_gradients: GradientAccumulator,
+
+    /// Calibration tokens for comparison
+    calibration_tokens: []const i32,
+
+    /// Repair metrics
+    metrics: RepairMetrics,
+
+    /// Interrupt flag for graceful cancellation
+    interrupt_flag: *std.atomic.Value(bool),
+
+    /// Reference model path (for loading layers)
+    reference_model_path: []const u8,
+
+    /// Start time of repair session
+    session_start_time: i64,
+
+    const Self = @This();
+
+    /// Initialize layer repair state
+    pub fn init(
+        allocator: std.mem.Allocator,
+        total_layers: u32,
+        memory_budget_gb: f32,
+        reference_path: []const u8,
+        interrupt_flag: *std.atomic.Value(bool),
+    ) !Self {
+        const path_copy = try allocator.dupe(u8, reference_path);
+        errdefer allocator.free(path_copy);
+
+        return Self{
+            .allocator = allocator,
+            .current_layer = 0,
+            .total_layers = total_layers,
+            .memory_budget_bytes = @intFromFloat(memory_budget_gb * 1024 * 1024 * 1024),
+            .current_memory_bytes = 0,
+            .high_prec_layer = null,
+            .accumulated_gradients = GradientAccumulator.init(allocator),
+            .calibration_tokens = &[_]i32{},
+            .metrics = RepairMetrics.init(),
+            .interrupt_flag = interrupt_flag,
+            .reference_model_path = path_copy,
+            .session_start_time = std.time.milliTimestamp(),
+        };
+    }
+
+    pub fn deinit(self: *Self) void {
+        if (self.high_prec_layer) |layer| {
+            layer.deinit(self.allocator);
+            self.allocator.destroy(layer);
+        }
+        self.accumulated_gradients.deinit();
+        self.allocator.free(self.reference_model_path);
+    }
+
+    /// Set calibration tokens for comparison
+    pub fn setCalibrationTokens(self: *Self, tokens: []const i32) void {
+        self.calibration_tokens = tokens;
+    }
+
+    /// Check if we should continue (not interrupted, within budget)
+    pub fn shouldContinue(self: *const Self) bool {
+        return !self.interrupt_flag.load(.monotonic);
+    }
+
+    /// Check if we have memory budget for loading a layer
+    pub fn hasMemoryBudget(self: *const Self, layer_size: usize) bool {
+        return self.current_memory_bytes + layer_size <= self.memory_budget_bytes;
+    }
+
+    /// Load a high-precision layer from disk
+    /// This is the core disk-paging operation
+    pub fn loadHighPrecLayer(self: *Self, layer_idx: u32) !*HighPrecLayer {
+        // Free existing layer if any
+        if (self.high_prec_layer) |old_layer| {
+            self.current_memory_bytes -= old_layer.size_bytes;
+            old_layer.deinit(self.allocator);
+            self.allocator.destroy(old_layer);
+            self.high_prec_layer = null;
+        }
+
+        // Construct layer file path
+        // Convention: {model_dir}/layers/layer_{idx}.f16
+        const layer_path = try std.fmt.allocPrint(
+            self.allocator,
+            "{s}/layers/layer_{d:0>3}.f16",
+            .{ self.reference_model_path, layer_idx },
+        );
+        defer self.allocator.free(layer_path);
+
+        // Open and read the layer file
+        const file = std.fs.cwd().openFile(layer_path, .{}) catch {
+            // If individual layer files don't exist, try loading from GGUF
+            logger.debug("Layer file not found, attempting GGUF extraction: {s}", .{layer_path});
+            return self.loadLayerFromGGUF(layer_idx);
+        };
+        defer file.close();
+
+        const stat = try file.stat();
+        const file_size = stat.size;
+
+        // Check memory budget
+        if (!self.hasMemoryBudget(file_size)) {
+            return error.InsufficientMemoryBudget;
+        }
+
+        // Allocate aligned buffer
+        const n_weights = file_size / 2; // f16 = 2 bytes each
+        const weights = try self.allocator.alignedAlloc(f16, 64, n_weights);
+        errdefer self.allocator.free(weights);
+
+        // Read weights
+        const bytes = std.mem.sliceAsBytes(weights);
+        const bytes_read = try file.readAll(bytes);
+        if (bytes_read != file_size) {
+            return error.IncompleteRead;
+        }
+
+        // Create layer struct
+        const layer = try self.allocator.create(HighPrecLayer);
+        layer.* = .{
+            .layer_idx = layer_idx,
+            .weights = weights,
+            .size_bytes = file_size,
+            .source_path = try self.allocator.dupe(u8, layer_path),
+            .source_quant = .F16,
+        };
+
+        self.high_prec_layer = layer;
+        self.current_memory_bytes += file_size;
+        self.metrics.memory_peak_bytes = @max(self.metrics.memory_peak_bytes, self.current_memory_bytes);
+
+        logger.debug("Loaded high-precision layer {d}: {d} MB", .{
+            layer_idx,
+            file_size / (1024 * 1024),
+        });
+
+        return layer;
+    }
+
+    /// Load layer from GGUF file (fallback when individual layer files don't exist)
+    fn loadLayerFromGGUF(self: *Self, layer_idx: u32) !*HighPrecLayer {
+        // This is a placeholder - actual implementation would use llama.cpp's
+        // tensor loading API to extract a specific layer
+
+        // For now, create a dummy layer for testing the infrastructure
+        const dummy_size: usize = 400 * 1024 * 1024; // 400MB dummy
+        const n_weights = dummy_size / 2;
+
+        if (!self.hasMemoryBudget(dummy_size)) {
+            return error.InsufficientMemoryBudget;
+        }
+
+        const weights = try self.allocator.alignedAlloc(f16, 64, n_weights);
+        errdefer self.allocator.free(weights);
+
+        // Initialize with zeros (placeholder)
+        @memset(std.mem.sliceAsBytes(weights), 0);
+
+        const layer = try self.allocator.create(HighPrecLayer);
+        layer.* = .{
+            .layer_idx = layer_idx,
+            .weights = weights,
+            .size_bytes = dummy_size,
+            .source_path = try self.allocator.dupe(u8, self.reference_model_path),
+            .source_quant = .F16,
+        };
+
+        self.high_prec_layer = layer;
+        self.current_memory_bytes += dummy_size;
+        self.metrics.memory_peak_bytes = @max(self.metrics.memory_peak_bytes, self.current_memory_bytes);
+
+        logger.debug("Loaded layer {d} from GGUF (placeholder): {d} MB", .{
+            layer_idx,
+            dummy_size / (1024 * 1024),
+        });
+
+        return layer;
+    }
+
+    /// Free the currently loaded high-precision layer
+    pub fn freeHighPrecLayer(self: *Self) void {
+        if (self.high_prec_layer) |layer| {
+            self.current_memory_bytes -= layer.size_bytes;
+            layer.deinit(self.allocator);
+            self.allocator.destroy(layer);
+            self.high_prec_layer = null;
+
+            logger.debug("Freed high-precision layer, memory now: {d} MB", .{
+                self.current_memory_bytes / (1024 * 1024),
+            });
+        }
+    }
+
+    /// Compute correction gradients for a layer
+    /// q2_output: Output from Q2_K model for calibration tokens
+    /// fp16_output: Output from FP16 layer for same tokens
+    pub fn computeCorrectionGradients(
+        self: *Self,
+        layer_idx: u32,
+        q2_output: []const f32,
+        fp16_output: []const f32,
+    ) !LayerRepairResult {
+        const start_time = std.time.milliTimestamp();
+
+        if (q2_output.len != fp16_output.len) {
+            return LayerRepairResult{
+                .layer_idx = layer_idx,
+                .error_before = 0.0,
+                .error_after = 0.0,
+                .gradient_norm = 0.0,
+                .time_ms = 0,
+                .success = false,
