+pub const QuantType = enum(u8) {
+    Q2_K = 0, // 2.96 bpw - Most aggressive, for FFN layers
+    Q3_K_S = 1, // 3.41 bpw - Balanced compression
+    Q3_K_M = 2, // 3.66 bpw - Better quality
+    Q4_K_M = 3, // 4.5 bpw  - Good for attention
+    Q4_K_S = 4, // 4.25 bpw - Smaller Q4
+    Q5_K_M = 5, // 5.5 bpw  - High quality
+    Q6_K = 6, // 6.5 bpw  - Critical layers (first/last)
+    Q8_0 = 7, // 8 bpw    - Reference quality
+    F16 = 8, // 16 bpw   - Full precision (disk-only for repair)
+
+    /// Get bits per weight for this quantization type
+    pub fn bitsPerWeight(self: QuantType) f32 {
+        return switch (self) {
+            .Q2_K => 2.96,
+            .Q3_K_S => 3.41,
+            .Q3_K_M => 3.66,
+            .Q4_K_M => 4.50,
+            .Q4_K_S => 4.25,
+            .Q5_K_M => 5.50,
+            .Q6_K => 6.50,
+            .Q8_0 => 8.50, // Includes scale factors
+            .F16 => 16.0,
+        };
+    }
+
+    /// Estimated perplexity increase vs F16 baseline
+    pub fn perplexityImpact(self: QuantType) f32 {
+        return switch (self) {
+            .Q2_K => 3.5, // Significant degradation
+            .Q3_K_S => 1.6, // Noticeable
+            .Q3_K_M => 0.86, // Acceptable
+            .Q4_K_M => 0.35, // Minor
+            .Q4_K_S => 0.40, // Minor
+            .Q5_K_M => 0.15, // Minimal
+            .Q6_K => 0.05, // Negligible
+            .Q8_0 => 0.01, // Essentially lossless
+            .F16 => 0.0, // Baseline
+        };
+    }
+
+    /// String representation for logging
+    pub fn toString(self: QuantType) []const u8 {
+        return switch (self) {
+            .Q2_K => "Q2_K",
+            .Q3_K_S => "Q3_K_S",
+            .Q3_K_M => "Q3_K_M",
+            .Q4_K_M => "Q4_K_M",
+            .Q4_K_S => "Q4_K_S",
+            .Q5_K_M => "Q5_K_M",
+            .Q6_K => "Q6_K",
+            .Q8_0 => "Q8_0",
+            .F16 => "F16",
+        };
+    }
+};
