+/// Layer type classification for mixed precision strategy
+pub const LayerType = enum(u8) {
+    embedding, // Token embeddings - keep high precision
+    attention_qkv, // Q, K, V projections - critical for logic
+    attention_output, // Output projection
+    ffn_gate, // FFN gate projection
+    ffn_up, // FFN up projection (largest)
+    ffn_down, // FFN down projection
+    norm, // Layer norms - always F32
+    output, // Final output layer - keep high precision
+};
+
+/// Per-layer quantization configuration
+pub const LayerQuantConfig = struct {
+    /// Layer index (0-indexed)
+    layer_idx: u32,
+    /// Quantization type for this layer
+    quant_type: QuantType,
+    /// Layer type (for strategy selection)
+    layer_type: LayerType,
+    /// Whether this layer is critical for model quality
+    is_critical: bool,
+    /// Measured perplexity impact when quantized (runtime updated)
+    perplexity_impact: f32,
+    /// Last time this layer was repaired (Unix timestamp)
