+
+    /// Check if this layer needs repair based on error magnitude
+    pub fn needsRepair(self: *const LayerQuantConfig, threshold: f32) bool {
+        return self.last_error_magnitude >= threshold;
+    }
+
+    /// Calculate repair priority (higher = more urgent)
+    pub fn repairPriority(self: *const LayerQuantConfig) f32 {
+        var priority: f32 = self.last_error_magnitude;
