+            @TypeOf(candidates.items[0]),
+            candidates.items,
+            {},
+            struct {
+                fn lessThan(_: void, a: @TypeOf(candidates.items[0]), b: @TypeOf(candidates.items[0])) bool {
+                    return a.priority > b.priority;
