+        q3_layers: u32,
+        q4_layers: u32,
+        q6_layers: u32,
+        critical_layers: u32,
+        repaired_layers: u32,
+        total_repairs: u32,
+    } {
+        var stats: @TypeOf(self.getStats()) = .{
+            .q2_layers = 0,
+            .q3_layers = 0,
+            .q4_layers = 0,
+            .q6_layers = 0,
+            .critical_layers = 0,
+            .repaired_layers = 0,
+            .total_repairs = 0,
+        };
+
+        for (self.layer_configs) |config| {
+            switch (config.quant_type) {
+                .Q2_K => stats.q2_layers += 1,
+                .Q3_K_S, .Q3_K_M => stats.q3_layers += 1,
+                .Q4_K_M, .Q4_K_S => stats.q4_layers += 1,
+                .Q6_K, .Q5_K_M => stats.q6_layers += 1,
+                else => {},
+            }
+            if (config.is_critical) stats.critical_layers += 1;
+            if (config.repair_count > 0) stats.repaired_layers += 1;
+            stats.total_repairs += config.repair_count;
+        }
+
+        return stats;
+    }
+};
+
+// =============================================================================
+// Tests
+// =============================================================================
+
+test "QuantType bits per weight" {
