+}
+
+test "QuantType perplexity impact ordering" {
+    // Q2_K should have highest impact, F16 should have zero
+    try std.testing.expect(QuantType.Q2_K.perplexityImpact() > QuantType.Q4_K_M.perplexityImpact());
+    try std.testing.expect(QuantType.Q4_K_M.perplexityImpact() > QuantType.F16.perplexityImpact());
+    try std.testing.expectApproxEqAbs(@as(f32, 0.0), QuantType.F16.perplexityImpact(), 0.001);
+}
+
+test "MixedPrecisionProfile createDefault" {
+    const allocator = std.testing.allocator;
+    var profile = try MixedPrecisionProfile.createDefault(allocator, 80, 4096);
+    defer profile.deinit();
+
+    try std.testing.expectEqual(@as(u32, 80), profile.n_layers);
