+
+    // First layer should be critical at Q6
+    try std.testing.expect(profile.layer_configs[0].is_critical);
+    try std.testing.expectEqual(QuantType.Q6_K, profile.layer_configs[0].quant_type);
+
+    // Last layer should also be critical
