+
+    // Middle layers should be Q2_K
+    try std.testing.expectEqual(QuantType.Q2_K, profile.layer_configs[40].quant_type);
+}
+
+test "MixedPrecisionProfile createAggressive" {
+    const allocator = std.testing.allocator;
+    var profile = try MixedPrecisionProfile.createAggressive(allocator, 80, 4096);
+    defer profile.deinit();
+
+    // Count Q2_K layers - should be most of them
+    var q2_count: u32 = 0;
+    for (profile.layer_configs) |config| {
+        if (config.quant_type == .Q2_K) q2_count += 1;
+    }
+
+    // All but first and last should be Q2_K
+    try std.testing.expectEqual(@as(u32, 78), q2_count);
+}
+
+test "LayerQuantConfig needsRepair" {
+    var config = LayerQuantConfig{
+        .layer_idx = 0,
+        .quant_type = .Q2_K,
+        .layer_type = .ffn_up,
+        .is_critical = false,
+        .perplexity_impact = 0.0,
+        .last_repaired = 0,
+        .repair_count = 0,
+        .last_error_magnitude = 0.05,
+    };
+
+    try std.testing.expect(config.needsRepair(0.01)); // Error > threshold
+    try std.testing.expect(!config.needsRepair(0.1)); // Error < threshold
+}

