+test "QHealingConfig defaults" {
+    const config = QHealingConfig{};
+    try std.testing.expect(config.enabled);
+    try std.testing.expectApproxEqAbs(@as(f32, 1.0), config.repair_memory_budget_gb, 0.01);
+    try std.testing.expectEqual(@as(u32, 8), config.max_layers_per_cycle);
+    try std.testing.expectEqual(LayerStrategy.round_robin, config.layer_strategy);
+}
+
+test "DeepSleepConfig defaults" {
+    const config = DeepSleepConfig{};
+    try std.testing.expect(config.enabled);
+    try std.testing.expectEqual(@as(i64, 300_000), config.min_idle_ms);
+    try std.testing.expectEqual(@as(i64, 900_000), config.max_duration_ms);
+}
+
+test "QHealingController init and deinit" {
+    const allocator = std.testing.allocator;
+
+    var controller = try QHealingController.init(allocator, QHealingConfig{}, 0x12345678);
+    defer controller.deinit();
+
+    try std.testing.expect(!controller.in_deep_sleep);
+    try std.testing.expectEqual(@as(u32, 0), controller.total_cycles);
+}
+
+test "QHealingController canEnterDeepSleep" {
+    const allocator = std.testing.allocator;
+
+    // Without reference model path, should not be able to enter
+    const config = QHealingConfig{};
+    var controller = try QHealingController.init(allocator, config, 0x12345678);
+    defer controller.deinit();
+
+    try std.testing.expect(!controller.canEnterDeepSleep());
+
+    // With reference model path, should be able to enter
+    controller.config.reference_model_path = "/some/path";
+    try std.testing.expect(controller.canEnterDeepSleep());
+}
+
+test "LayerStrategy selection" {
+    const allocator = std.testing.allocator;
+
+    const config = QHealingConfig{
+        .reference_model_path = "/some/path",
+        .max_layers_per_cycle = 4,
+    };
+
+    var controller = try QHealingController.init(allocator, config, 0x12345678);
+    defer controller.deinit();
+
+    // Test entering deep sleep
+    const entered = try controller.enterDeepSleep(80);
+    try std.testing.expect(entered);
+    try std.testing.expect(controller.in_deep_sleep);
+
+    // Exit and verify
+    controller.exitDeepSleep();
+    try std.testing.expect(!controller.in_deep_sleep);
+}
